 1	import { type FC, type Ref, useState } from 'react';
 2	import useProviderInventory from 'src/modules/Providers/hooks/useProviderInventory';
 3	
 4	import type { OpenShiftNetworkAttachmentDefinition, V1beta1Provider } from '@kubev2v/types';
 5	import {
 6	  Dropdown,
 7	  DropdownItem,
 8	  DropdownList,
 9	  MenuToggle,
10	  type MenuToggleElement,
11	} from '@patternfly/react-core';
12	import { DEFAULT_NETWORK } from '@utils/constants';
13	
14	import { getNetworkName } from './utils/getNetworkName';
15	
16	type ProviderDefaultTransferNetworkDropdownProps = {
17	  value: string | number;
18	  onChange: (arg0: string) => void;
19	  provider: V1beta1Provider;
20	};
21	
22	const ProviderDefaultTransferNetworkDropdown: FC<ProviderDefaultTransferNetworkDropdownProps> = ({
23	  onChange,
24	  provider,
25	  value,
26	}) => {
27	  const [isOpen, setIsOpen] = useState(false);
28	  const onToggleClick = () => {
29	    setIsOpen((open) => !open);
30	  };
31	  const onSelect = () => {
32	    setIsOpen(false);
33	  };
34	
35	  const { inventory: networks } = useProviderInventory<OpenShiftNetworkAttachmentDefinition[]>({
36	    provider,
37	    subPath: 'networkattachmentdefinitions?detail=4',
38	  });
39	
40	  const currentSelectedName = getNetworkName(value);
41	
42	  const dropdownItems = [
43	    <DropdownItem
44	      value={0}
45	      key={DEFAULT_NETWORK}
46	      description={DEFAULT_NETWORK}
47	      onClick={() => {
48	        onChange('');
49	      }}
50	    >
51	      {DEFAULT_NETWORK}
52	    </DropdownItem>,
53	    ...(networks ?? []).map((network) => (
54	      <DropdownItem
55	        value={1}
56	        key={network.name}
57	        description={network.namespace}
58	        onClick={() => {
59	          onChange(`${network.namespace}/${network.name}`);
60	        }}
61	      >
62	        {network.name}
63	      </DropdownItem>
64	    )),
65	  ];
66	
67	  return (
68	    <Dropdown
69	      isOpen={isOpen}
70	      onOpenChange={setIsOpen}
71	      onSelect={onSelect}
72	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
73	        <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen} variant={'default'}>
74	          {currentSelectedName}
75	        </MenuToggle>
76	      )}
77	      shouldFocusToggleOnSelect
78	      popperProps={{
79	        position: 'right',
80	      }}
81	      isScrollable={true}
82	    >
83	      <DropdownList>{dropdownItems}</DropdownList>
84	    </Dropdown>
85	  );
86	};
87	
88	export default ProviderDefaultTransferNetworkDropdown;

